    bench.name("AsMapGetMappedAS" + name_suffix).run([&] {
        for (auto& addr : addrs) {
            const auto mapped_as{netgroupman.GetMappedAS(addr)};
            assert((mapped_as > 0) == check);
        }
    });
}
